const LocalSpotlight = ({ step, hasPumpedOnce }: { step: SequenceStep, hasPumpedOnce: boolean }) => {
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const animRef = useRef<number | null>(null);
    const config = SCENE_STEPS_CONFIG[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.getElementById(config.targetId);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) setTargetRect(rect);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        if (!targetRect) return;
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const duration = 1300;
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            const nextR = 2000 - (2000 - targetR) * easeOut;
            setAnimatedRadius(nextR);
            if (progress < 1) animRef.current = requestAnimationFrame(animate);
        };
        animRef.current = requestAnimationFrame(animate);
        return () => { if (animRef.current !== null) cancelAnimationFrame(animRef.current); };
    }, [step, !!targetRect]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current !== null) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    if (!config || !targetRect) return null;

    const { top, left, width, height } = targetRect;
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles: React.CSSProperties = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';
    const cardinalBuffer = 12;

    switch (config.direction) {
        case 'top': pointerStyles = { left: centerX, top: top - cardinalBuffer, transform: 'translate(-50%, -100%)' }; iconRotation = 'rotate(180deg)'; animationClass = 'animate-bounce-reverse'; containerLayout = 'flex-col-reverse'; labelMargin = 'mb-3'; break;
        case 'bottom': pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' }; iconRotation = 'rotate(0deg)'; animationClass = 'animate-bounce'; containerLayout = 'flex-col'; labelMargin = 'mt-3'; break;
        case 'left': pointerStyles = { left: left - cardinalBuffer, top: centerY, transform: 'translate(-100%, -50%)' }; iconRotation = 'rotate(90deg)'; animationClass = 'animate-bounce-x-reverse'; containerLayout = 'flex-row-reverse'; labelMargin = 'mr-3'; break;
        case 'right': pointerStyles = { left: left + width + cardinalBuffer, top: centerY, transform: 'translateY(-50%)' }; iconRotation = 'rotate(-90deg)'; animationClass = 'animate-bounce-x'; containerLayout = 'flex-row'; labelMargin = 'ml-3'; break;
        default: pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' }; iconRotation = 'rotate(0deg)'; animationClass = 'animate-bounce'; containerLayout = 'flex-col'; labelMargin = 'mt-3'; break;
    }

    return (
        <div className="fixed inset-0 z-[3050] pointer-events-none overflow-hidden">
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs><mask id="tutorial-mask-local"><rect width="100%" height="100%" fill="white" /><circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" /></mask></defs>
                <rect width="100%" height="100%" fill={`rgba(0,0,0,${Math.min(0.75, 1.5 - (animatedRadius / 1000))})`} mask="url(#tutorial-mask-local)" />
            </svg>
            <div className="absolute animate-in fade-in zoom-in-95 duration-300" style={pointerStyles}><div className={`flex items-center ${containerLayout} ${animationClass}`}><Pointer className="w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20" style={{ transform: iconRotation }} /><div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase rounded-full shadow-2xl border-2 border-amber-400`}>{(step === 'WAIT_PUMP' && hasPumpedOnce) ? "Keep Pump!" : config.label}</div></div></div>
        </div>
    );
};

const TutorialScene: React.FC = () => {
    const { state, actions } = useGame();
    const [seq, setSeq] = useState<SequenceStep>('IDLE');
    const [currentStep, setCurrentStep] = useState(0);
    const [temp, setTemp] = useState(0); 
    const [isPumping, setIsPumping] = useState(false);
    const [hasPumpedOnce, setHasPumpedOnce] = useState(false);
    const [showFlash, setShowFlash] = useState(false);
    const [isStarted, setIsStarted] = useState(false);
    const [showSkipConfirm, setShowSkipConfirm] = useState(false);
    const mode = state.activeTutorialScene || 'PROLOGUE';

    useEffect(() => {
        if (seq === 'HEAT_CONFIRM' || seq === 'WAIT_CONTINUE_BELLOWS' || seq === 'WAIT_PUMP') {
            const timer = setInterval(() => { setTemp(prev => prev > 29.1 ? prev - 0.12 : prev); }, 50);
            return () => clearInterval(timer);
        }
    }, [seq]);

    const bgImage = useMemo(() => {
        if (mode === 'PROLOGUE' || (seq === 'IDLE' && !isStarted)) return 'forge_ruined_bg.png';
        if (seq === 'POST_REPLACE_TALK' || seq === 'WAIT_HEAT') return 'forge_fixed_bg.png';
        if (temp >= 99.5) return 'forge_hot_bg.png';
        return 'forge_start_bg.png';
    }, [mode, seq, temp, isStarted]);

    const handleNext = () => {
        if (mode === 'PROLOGUE') {
            if (currentStep < 4) setCurrentStep(prev => prev + 1); else actions.completePrologue();
        } else {
            if (seq === 'POST_REPLACE_TALK') { if (currentStep < 1) setCurrentStep(prev => prev + 1); else setSeq('WAIT_HEAT'); }
            else if (seq === 'HEAT_CONFIRM') { setSeq('WAIT_CONTINUE_BELLOWS'); setCurrentStep(0); }
            else if (seq === 'WAIT_CONTINUE_BELLOWS') { if (currentStep < 1) setCurrentStep(prev => prev + 1); else setSeq('WAIT_PUMP'); }
            else if (seq === 'FINAL_TALK') { actions.setTutorialScene(null); actions.setTutorialStep('CRAFT_PROMPT'); }
        }
    };

    return (
        <div className="fixed inset-0 z-[3000] bg-stone-950 overflow-hidden flex flex-col items-center justify-center cursor-pointer px-safe" onClick={() => !isStarted ? (mode === 'FURNACE_RESTORED' ? (setShowFlash(true), setTimeout(() => { setIsStarted(true); setSeq('POST_REPLACE_TALK'); }, 50), setTimeout(() => setShowFlash(false), 800)) : setIsStarted(true)) : null}>
            <div className="absolute inset-0 z-0"><img src={getAssetUrl(bgImage)} className="w-full h-full object-cover opacity-80" /></div>
            <div className="absolute top-4 right-4 z-[6000]"><button onClick={(e) => { e.stopPropagation(); setShowSkipConfirm(true); }} className="flex items-center gap-1.5 px-3 py-1.5 bg-stone-900 border border-stone-700 text-stone-300 rounded-full text-[10px] font-black uppercase"><FastForward className="w-3 h-3" /> Skip</button></div>
            {isStarted && (seq === 'WAIT_HEAT' || seq === 'WAIT_PUMP') && <LocalSpotlight step={seq} hasPumpedOnce={hasPumpedOnce} />}
            {isStarted && <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl pointer-events-none"><DialogueBox speaker="Lockhart" text={mode === 'PROLOGUE' ? SCRIPTS[`PROLOGUE_${currentStep}`].text : seq === 'WAIT_HEAT' ? SCRIPTS.FURNACE_HEAT_PROMPT.text : seq === 'FINAL_TALK' ? SCRIPTS.FURNACE_MAXED.text : SCRIPTS[`FURNACE_${currentStep}`]?.text || "..."} options={['WAIT_HEAT', 'WAIT_PUMP'].includes(seq) ? [] : [{ label: "Continue", action: handleNext, variant: 'primary' }]} className="w-full relative pointer-events-auto" /></div>}
            {mode === 'FURNACE_RESTORED' && isStarted && (
                <div className="absolute top-[15dvh] right-[5vw] z-[3040] flex flex-col items-center gap-6"><div className="w-7 h-48 bg-stone-950 rounded-full border-2 border-stone-800 relative"><div className="absolute inset-1 rounded-full overflow-hidden"><div className={`absolute bottom-0 left-0 right-0 rounded-full transition-all ${temp > 80 ? 'bg-red-600' : 'bg-amber-500'}`} style={{ height: `${temp}%` }} /></div></div>
                <button id="tutorial-bellows" onClick={(e) => { e.stopPropagation(); setTemp(prev => Math.min(100, prev + 5)); setHasPumpedOnce(true); if (temp + 5 >= 100) setSeq('FINAL_TALK'); }} disabled={seq !== 'WAIT_PUMP'} className={`w-16 h-16 rounded-full border-4 ${seq === 'WAIT_PUMP' ? 'bg-stone-800 border-amber-500' : 'bg-stone-900 grayscale opacity-40'}`}><Zap className="text-amber-400" /></button>
                <button id="tutorial-heat" onClick={(e) => { e.stopPropagation(); setTemp(80); setSeq('HEAT_CONFIRM'); }} disabled={seq !== 'WAIT_HEAT'} className={`w-14 h-14 rounded-xl border-2 ${seq === 'WAIT_HEAT' ? 'bg-orange-900 border-orange-500' : 'bg-stone-900 grayscale opacity-40'}`}><Flame className="text-orange-400" /></button></div>
            )}
            <ConfirmationModal isOpen={showSkipConfirm} title="Skip?" message="Unlock all systems immediately?" onConfirm={() => actions.completeTutorial()} onCancel={() => setShowSkipConfirm(false)} isDanger />
        </div>
    );
};

