    PAY_NOW: { speaker: "Garrick", text: "Hand over the coin, and the future is yours." },
    TALK_TO_GARRICK_AFTER_PURCHASE: { speaker: "Lockhart", text: "I should say goodbye to Garrick before I leave." },
    LEAVE_MARKET_GUIDE: { speaker: "Garrick", text: "Safe travels, Lockhart. Don't let those embers go cold again." },
};

export const MarketTutorialOverlay = ({ step }: { step: string }) => {
    const { actions } = useGame();
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const config = SCENE_STEPS_CONFIG[step];
    const script = SCRIPTS[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.querySelector(`[data-tutorial-id="${config.targetId}"]`);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) setTargetRect(rect);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    useEffect(() => {
        if (!targetRect) return;
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / 1300, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            setAnimatedRadius(2000 - (2000 - targetR) * easeOut);
            if (progress < 1) requestAnimationFrame(animate);
        };
        requestAnimationFrame(animate);
    }, [!!targetRect]);

    if (!config) return null;
    const { top = 0, left = 0, width = 0, height = 0 } = targetRect || {};
    const centerX = left + width / 2; const centerY = top + height / 2;

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden">
            <svg className="absolute inset-0 w-full h-full"><defs><mask id="m-mask"><rect width="100%" height="100%" fill="white" />{targetRect && <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />}</mask></defs><rect width="100%" height="100%" fill="rgba(0,0,0,0.75)" mask="url(#m-mask)" /></svg>
            {targetRect && <div className="absolute" style={{ top: centerY, left: centerX, transform: 'translate(-50%, -50%)' }}>
                <div className="flex flex-col items-center animate-bounce">
                    <Pointer className="w-10 h-10 text-amber-400" />
                    <div className="px-4 py-1.5 bg-amber-600 text-white text-[10px] font-black uppercase rounded-full border-2 border-amber-400 whitespace-nowrap">{config.label}</div>
                </div>
            </div>}
            {script && <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[90vw] max-w-4xl pointer-events-auto">
                <DialogueBox speaker={script.speaker} text={script.text} options={step === 'BROWSE_GOODS_GUIDE' ? [{ label: "Browse", action: () => actions.setTutorialStep('FURNACE_GUIDE'), variant: 'primary' }] : step === 'TALK_TO_GARRICK_AFTER_PURCHASE' ? [{ label: "Talk", action: () => actions.setTutorialStep('LEAVE_MARKET_GUIDE'), variant: 'primary' }] : []} />
            </div>}
        </div>
    );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Heart } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { FloatingHeart } from '../hooks/useMarket';

export const GarrickSprite = ({ floatingHearts }: { floatingHearts: FloatingHeart[] }) => {
    const [frame, setFrame] = useState(0);
    const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    const blink = useCallback(() => {
        setFrame(1);
        setTimeout(() => {
            setFrame(2);
            setTimeout(() => {
                setFrame(1);
                setTimeout(() => {
                    setFrame(0);
                    scheduleNextBlink();
                }, 80);
            }, 100);
        }, 80);
    }, []);

    const scheduleNextBlink = useCallback(() => {
        timerRef.current = setTimeout(blink, 3000 + Math.random() * 4000);
    }, [blink]);

    useEffect(() => {
        scheduleNextBlink();
        return () => { if (timerRef.current) clearTimeout(timerRef.current); };
    }, [scheduleNextBlink]);

    return (
        <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
            <div className="absolute bottom-[25%] left-1/2 -translate-x-1/2 w-80 h-80 bg-amber-500/10 blur-[100px] rounded-full -z-10 animate-pulse"></div>
            {floatingHearts.map(heart => (
                <Heart key={heart.id} className="absolute animate-heart fill-pink-500 text-pink-400 z-0" style={{ left: `${heart.left}%`, bottom: '40%', width: heart.size, height: heart.size, animationDelay: `${heart.delay}s`, '--wobble': `${(Math.random() - 0.5) * 60}px` } as React.CSSProperties} />
            ))}
            <div className="relative h-[75dvh] md:h-[110dvh] bottom-[12dvh] md:bottom-0 md:translate-y-[15dvh] z-10" style={{ aspectRatio: '453.3 / 1058' }}>
                <div className="h-full w-full" style={{ backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`, backgroundSize: '300% 100%', backgroundPosition: `${frame * 50}% 0%`, imageRendering: 'pixelated', filter: 'drop-shadow(0 0 50px rgba(0,0,0,0.9))' }} />
            </div>
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-3xl rounded-full -z-10"></div>
        </div>
    );
};

import React from 'react';
import { Package, Coins, Lock } from 'lucide-react';
import { getAssetUrl } from '../../../utils';

interface MarketItemCardProps {
    item: any;
    stock: number;
    inventoryCount: number;
    multiplier: number;
    isLocked: boolean;
    onAdd: (id: string, count: number) => void;
    onSetMultiplier: (id: string, val: number) => void;
}

export const MarketItemCard: React.FC<MarketItemCardProps> = ({ item, stock, inventoryCount, multiplier, isLocked, onAdd, onSetMultiplier }) => {
    const isSoldOut = stock <= 0;
    const meta = item.meta;

    return (
        <div data-tutorial-id={item.id === 'furnace' ? 'FURNACE_ITEM' : undefined} className={`relative flex flex-col items-center p-2 rounded-2xl border transition-all h-[150px] md:h-[220px] justify-between overflow-hidden shadow-md ${isSoldOut ? 'bg-stone-900 border-stone-800 opacity-40 grayscale' : 'bg-stone-850 border-stone-800 hover:border-stone-600'}`}>
            {isLocked && <div className="absolute top-1 left-1 p-1 bg-red-900/80 rounded border border-red-500 z-20"><Lock className="w-2 h-2 text-white" /></div>}
            {inventoryCount > 0 && <div className="absolute top-1 left-1 px-1 py-0.5 rounded text-[6px] font-black uppercase border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-1"><Package className="w-2 h-2" />{inventoryCount}</div>}
            <div className={`absolute top-1 right-1 px-1 py-0.5 rounded text-[6px] font-black tracking-tighter border z-10 ${stock > 0 ? 'bg-emerald-950/60 text-emerald-400 border-emerald-500/40' : 'bg-red-950/60 text-red-500 border-red-500/40'}`}>{isSoldOut ? 'X' : stock}</div>

            <div className={`flex-1 w-full flex items-center justify-center transition-all mt-1 rounded-lg ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 active:scale-95'}`} onClick={() => !isSoldOut && onAdd(item.id, multiplier)}>
                <img src={getAssetUrl(`${item.id}.png`)} className="w-10 h-10 md:w-24 md:h-24 object-contain drop-shadow-md" />
            </div>

            {!isSoldOut && meta.type !== 'KEY_ITEM' && meta.type !== 'SCROLL' && (
                <div className="flex gap-1 mb-1 scale-75 md:scale-100">
                    {[1, 5, 10].map(v => <button key={v} disabled={stock < v} onClick={() => onSetMultiplier(item.id, v)} className={`w-5 h-5 md:w-7 md:h-7 rounded-full border text-[7px] font-black transition-all ${multiplier === v ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-900 border-stone-700 text-stone-500 hover:text-stone-300'}`}>{v}</button>)}
