    TALK_TO_GARRICK_AFTER_PURCHASE: { speaker: "Lockhart", text: "I should say goodbye to Garrick before I leave." },
    LEAVE_MARKET_GUIDE: { speaker: "Garrick", text: "Safe travels, Lockhart. Don't let those embers go cold again." },
};

export const MarketTutorialOverlay = ({ step }: { step: string }) => {
    const { actions } = useGame();
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const config = SCENE_STEPS_CONFIG[step];
    const script = SCRIPTS[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.querySelector(`[data-tutorial-id="${config.targetId}"]`);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) setTargetRect(rect);
            else setTargetRect(null);
        } else {
            setTargetRect(null);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    useEffect(() => {
        if (!targetRect) return;
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / 1300, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            setAnimatedRadius(2000 - (2000 - targetR) * easeOut);
            if (progress < 1) requestAnimationFrame(animate);
        };
        requestAnimationFrame(animate);
    }, [!!targetRect]);

    if (!config) return null;

    const { top = 0, left = 0, width = 0, height = 0 } = targetRect || {};
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles: React.CSSProperties = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';
    const cardinalBuffer = 12;

    switch (config.direction) {
        case 'top':
            pointerStyles = { left: centerX, top: top - cardinalBuffer, transform: 'translate(-50%, -100%)' };
            iconRotation = 'rotate(180deg)';
            animationClass = 'animate-bounce-reverse';
            containerLayout = 'flex-col-reverse';
            labelMargin = 'mb-3';
            break;
        case 'bottom':
            pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' };
            iconRotation = 'rotate(0deg)';
            animationClass = 'animate-bounce';
            containerLayout = 'flex-col';
            labelMargin = 'mt-3';
            break;
        case 'left':
            pointerStyles = { left: left - cardinalBuffer, top: centerY, transform: 'translate(-100%, -50%)' };
            iconRotation = 'rotate(90deg)';
            animationClass = 'animate-bounce-x-reverse';
            containerLayout = 'flex-row-reverse';
            labelMargin = 'mr-3';
            break;
        case 'right':
            pointerStyles = { left: left + width + cardinalBuffer, top: centerY, transform: 'translateY(-50%)' };
            iconRotation = 'rotate(-90deg)';
            animationClass = 'animate-bounce-x';
            containerLayout = 'flex-row';
            labelMargin = 'ml-3';
            break;
        default:
            pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' };
            iconRotation = 'rotate(0deg)';
            animationClass = 'animate-bounce';
            containerLayout = 'flex-col';
            labelMargin = 'mt-3';
            break;
    }

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden">
            <svg className="absolute inset-0 w-full h-full">
                <defs>
                    <mask id="m-mask">
                        <rect width="100%" height="100%" fill="white" />
                        {targetRect && <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />}
                    </mask>
                </defs>
                <rect width="100%" height="100%" fill="rgba(0,0,0,0.75)" mask="url(#m-mask)" />
            </svg>

            {targetRect && (
                <div 
                    className="absolute animate-in fade-in zoom-in-95 duration-300" 
                    style={pointerStyles}
                >
                    <div className={`flex items-center ${containerLayout} ${animationClass}`}>
                        <Pointer 
                            className="w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]" 
                            style={{ transform: iconRotation }} 
                        />
                        <div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase tracking-widest rounded-full shadow-2xl border-2 border-amber-400 whitespace-nowrap`}>
                            {config.label}
                        </div>
                    </div>
                </div>
            )}

            {script && (
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[90vw] max-w-4xl pointer-events-auto">
                    <DialogueBox 
                        speaker={script.speaker} 
                        text={script.text} 
                        options={
                            step === 'BROWSE_GOODS_GUIDE' 
                                ? [{ label: "Browse", action: () => actions.setTutorialStep('FURNACE_GUIDE'), variant: 'primary' }] 
                                : step === 'TALK_TO_GARRICK_AFTER_PURCHASE' 
                                    ? [{ label: "Talk", action: () => actions.setTutorialStep('LEAVE_MARKET_GUIDE'), variant: 'primary' }] 
                                    : []
                        } 
                    />
                </div>
            )}
        </div>
    );
};

import React, { createContext, useContext, useReducer, useMemo, useEffect, useRef } from 'react';
import { GameContextType, GameState } from '../types/index';
import { gameReducer } from '../state/gameReducer';
import { createInitialGameState } from '../state/initial-game-state';
import { EquipmentItem, EquipmentSlotType } from '../types/inventory';
import { ShopCustomer } from '../types/shop';
import { Mercenary } from '../models/Mercenary';
import { PrimaryStats } from '../models/Stats';
import { GAME_CONFIG } from '../config/game-config';
import { getEnergyCost } from '../utils/craftingLogic';
import { GameEvent } from '../types/events';
import { saveToSlot } from '../utils/saveSystem';

const GameContext = createContext<GameContextType | undefined>(undefined);

export const useGame = () => {
  const context = useContext(GameContext);
  if (context === undefined) {
    throw new Error('useGame must be used within a GameProvider');
  }
  return context;
};

interface GameProviderProps {
    initialSlotIndex?: number;
    children: React.ReactNode;
}

export const GameProvider: React.FC<GameProviderProps> = ({ children, initialSlotIndex = 0 }) => {
  const [state, dispatch] = useReducer(gameReducer, undefined, createInitialGameState);

  const currentSlotRef = useRef(initialSlotIndex);
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const prevDayRef = useRef(state.stats.day);
  useEffect(() => {
    if (state.stats.day === prevDayRef.current + 1) {
      saveToSlot(currentSlotRef.current, state);
    }
    prevDayRef.current = state.stats.day;
  }, [state.stats.day, state]);

  // Debug: Tutorial Step Logging
  useEffect(() => {
      const scene = state.activeTutorialScene || 'NONE';
      const step = state.tutorialStep || 'NONE (Active Gameplay)';
      console.log(
          `%c[Tutorial Tracker] Scene: ${scene} | Step: ${step}`, 
          'color: #fbbf24; font-weight: bold; background: #1c1917; padding: 2px 6px; border-radius: 4px; border: 1px solid #fbbf24;'
      );
  }, [state.activeTutorialScene, state.tutorialStep]);

  useEffect(() => {
      if (!state.toast?.visible && state.toastQueue.length > 0) {
          const processTimer = setTimeout(() => {
              dispatch({ type: 'POP_NEXT_TOAST' });
          }, 150);
          return () => clearTimeout(processTimer);
      }
      if (state.toast?.visible) {
          const hideTimer = setTimeout(() => {
              dispatch({ type: 'HIDE_TOAST' });
          }, 3000);
          return () => clearTimeout(hideTimer);
      }
  }, [state.toast?.visible, state.toastQueue.length]);

  const triggerEnergyHighlight = () => {
      dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: true } });
      setTimeout(() => {
          dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: false } });
      }, 3000);
  };

  const showToast = (message: string) => {
      dispatch({ type: 'SHOW_TOAST', payload: message });
  };

  const actions = useMemo(() => ({
    repairItem: () => {
        if (stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.REPAIR) { triggerEnergyHighlight(); return; }
        dispatch({ type: 'REPAIR_WORK' });
    },
    rest: () => dispatch({ type: 'SLEEP' }),
    confirmSleep: () => dispatch({ type: 'CONFIRM_SLEEP' }),
    closeRest: () => dispatch({ type: 'CLOSE_SLEEP_MODAL' }),
    triggerEvent: (event: GameEvent) => dispatch({ type: 'TRIGGER_EVENT', payload: event }),
    handleEventOption: (action: () => void) => { action(); dispatch({ type: 'CLOSE_EVENT' }); },
    closeEvent: () => dispatch({ type: 'CLOSE_EVENT' }),
    saveGame: (slotIndex?: number) => {
        const targetSlot = slotIndex !== undefined ? slotIndex : currentSlotRef.current;
        const success = saveToSlot(targetSlot, stateRef.current);
        if (success) { currentSlotRef.current = targetSlot; showToast(`Progress saved to Slot ${targetSlot + 1}.`); }
    },
    loadGame: (loadedState: GameState) => dispatch({ type: 'LOAD_GAME', payload: loadedState }),
    startCrafting: (item: EquipmentItem) => {
        const masteryCount = stateRef.current.craftingMastery[item.id] || 0;
        const energyCost = getEnergyCost(item, masteryCount);
        if (stateRef.current.stats.energy < energyCost) { triggerEnergyHighlight(); return; }
        dispatch({ type: 'START_CRAFTING', payload: { item } });
    },
    cancelCrafting: (item: EquipmentItem) => dispatch({ type: 'CANCEL_CRAFTING', payload: { item } }),
    finishCrafting: (item: EquipmentItem, quality: number, bonus?: number, masteryGain?: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality, bonus, masteryGain } }),
    craftItem: (item: EquipmentItem, quality: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality } }),
    dismissCraftingResult: () => dispatch({ type: 'DISMISS_CRAFTING_RESULT' }),
    dismissTierUnlock: () => dispatch({ type: 'DISMISS_TIER_UNLOCK' }),
    buyItems: (items: { id: string; count: number }[], totalCost: number) => dispatch({ type: 'BUY_MARKET_ITEMS', payload: { items, totalCost } }),
    sellItem: (itemId: string, count: number, price: number, equipmentInstanceId?: string, customer?: Mercenary) =>
        dispatch({ type: 'SELL_ITEM', payload: { itemId, count, price, equipmentInstanceId, customer } }),
    toggleShop: () => {
        if (!stateRef.current.forge.isShopOpen && stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.OPEN_SHOP) { triggerEnergyHighlight(); return; }
        dispatch({ type: 'TOGGLE_SHOP' });
    },
    addMercenary: (merc: Mercenary) => dispatch({ type: 'ADD_KNOWN_MERCENARY', payload: merc }),
    scoutMercenary: (merc: Mercenary, cost: number) => dispatch({ type: 'SCOUT_MERCENARY', payload: { mercenary: merc, cost } }),
    consumeItem: (id: string, count: number) => dispatch({ type: 'PAY_COST', payload: { items: [{ id, count }] } }),
    enqueueCustomer: (customer: ShopCustomer) => dispatch({ type: 'ENQUEUE_CUSTOMER', payload: customer }),
    nextCustomer: () => dispatch({ type: 'NEXT_CUSTOMER' }),
    dismissCustomer: () => dispatch({ type: 'DISMISS_CUSTOMER' }),
    refuseCustomer: (mercenaryId: string, affinityLoss: number) => dispatch({ type: 'REFUSE_CUSTOMER', payload: { mercenaryId, affinityLoss } }),
    setCrafting: (isCrafting: boolean) => dispatch({ type: 'SET_CRAFTING', payload: isCrafting }),
    updateForgeStatus: (temp: number) => dispatch({ type: 'UPDATE_FORGE_STATUS', payload: { temp } }),
    updateMercenaryStats: (mercenaryId: string, stats: PrimaryStats) => dispatch({ type: 'UPDATE_MERCENARY_STATS', payload: { mercenaryId, stats } }),
    toggleJournal: () => dispatch({ type: 'TOGGLE_JOURNAL' }),
    hireMercenary: (mercenaryId: string, cost: number) => dispatch({ type: 'HIRE_MERCENARY', payload: { mercenaryId, cost } }),
    fireMercenary: (mercenaryId: string) => dispatch({ type: 'FIRE_MERCENARY', payload: { mercenaryId } }),
    giveGift: (mercenaryId: string, itemId: string) => dispatch({ type: 'GIVE_GIFT', payload: { mercenaryId, itemId } }),
    talkMercenary: (mercenaryId: string) => dispatch({ type: 'TALK_MERCENARY', payload: { mercenaryId } }),
    talkGarrick: () => dispatch({ type: 'TALK_GARRICK' }),
    giftGarrick: (payload: { itemId: string }) => dispatch({ type: 'GIFT_GARRICK', payload }),
    startExpedition: (dungeonId: string, partyIds: string[]) => dispatch({ type: 'START_EXPEDITION', payload: { dungeonId, partyIds } }),
    completeExpedition: (expeditionId: string) => dispatch({ type: 'COMPLETE_EXPEDITION', payload: { expeditionId } }),
    abortExpedition: (expeditionId: string) => dispatch({ type: 'ABORT_EXPEDITION', payload: { expeditionId } }),
    claimExpedition: (expeditionId: string) => dispatch({ type: 'CLAIM_EXPEDITION', payload: { expeditionId } }),
    dismissDungeonResult: () => dispatch({ type: 'DISMISS_DUNGEON_RESULT' }),
    equipItem: (mercenaryId: string, inventoryItemId: string) => dispatch({ type: 'EQUIP_ITEM', payload: { mercenaryId, inventoryItemId } }),
    unequipItem: (mercenaryId: string, slot: EquipmentSlotType) => dispatch({ type: 'UNEQUIP_ITEM', payload: { mercenaryId, slot } }),
    useItem: (itemId: string) => dispatch({ type: 'USE_ITEM', payload: { itemId } }),
    toggleLockItem: (itemId: string) => dispatch({ type: 'TOGGLE_LOCK_ITEM', payload: { itemId } }),
    allocateStat: (mercenaryId: string, stat: keyof PrimaryStats) => dispatch({ type: 'ALLOCATE_STAT', payload: { mercenaryId, stat } }),
    startManualAssault: (dungeonId: string, partyIds: string[]) => 
        dispatch({ type: 'START_MANUAL_DUNGEON', payload: { dungeonId, partyIds } }),
    moveInManualDungeon: (dx: number, dy: number) => 
        dispatch({ type: 'MOVE_MANUAL_DUNGEON', payload: { x: dx, y: dy } }),
    finishManualAssault: () => dispatch({ type: 'FINISH_MANUAL_DUNGEON' }),
    retreatFromManualDungeon: () => dispatch({ type: 'RETREAT_MANUAL_DUNGEON' }),
    toggleManualDungeonOverlay: (show: boolean) => dispatch({ type: 'TOGGLE_MANUAL_DUNGEON_OVERLAY', payload: show }),
    rescueMercenary: (npcId: string) => dispatch({ type: 'RESCUE_NPC', payload: { npcId } }),
    startCombatManual: () => dispatch({ type: 'START_COMBAT_MANUAL' }),
    resolveCombatManual: (win: boolean, flee: boolean, finalParty: any[]) => 
        dispatch({ type: 'RESOLVE_COMBAT_MANUAL', payload: { win, flee, finalParty } }),
    triggerEnergyHighlight,
    showToast,
    hideToast: () => dispatch({ type: 'HIDE_TOAST' }),
    setTutorialStep: (step: GameState['tutorialStep']) => dispatch({ type: 'SET_TUTORIAL_STEP', payload: step }),
    setTutorialScene: (mode: GameState['activeTutorialScene']) => dispatch({ type: 'SET_ACTIVE_TUTORIAL_SCENE', payload: mode }),
    completePrologue: () => dispatch({ type: 'COMPLETE_PROLOGUE' }),
    completeTutorial: () => dispatch({ type: 'COMPLETE_TUTORIAL' }),
    dismissTutorialComplete: () => dispatch({ type: 'DISMISS_TUTORIAL_COMPLETE' }),
    updateSettings: (settings: Partial<GameState['settings']>) => dispatch({ type: 'UPDATE_SETTINGS', payload: settings }),
  }), [dispatch]); 

  return (
    <GameContext.Provider value={{ state, actions }}>
      {children}
    </GameContext.Provider>
  );
};

export { GameContext };

