type TutorialDirection = 'top' | 'bottom' | 'left' | 'right' | 'topleft' | 'topright' | 'bottomleft' | 'bottomright';
interface StepConfig {
    targetId: string;
    label: string;
    direction: TutorialDirection;
}

const TUTORIAL_STEPS_CONFIG: Record<string, StepConfig> = {
    MARKET_GUIDE: { targetId: 'MARKET_TAB', label: 'Visit the Market', direction: 'bottom' },
    FORGE_TAB_GUIDE: { targetId: 'FORGE_TAB', label: 'Open Forge', direction: 'bottom' },
    SELECT_SWORD_GUIDE: { targetId: 'SWORD_RECIPE', label: 'Select Sword', direction: 'bottom' },
    START_FORGING_GUIDE: { targetId: 'START_FORGING_BUTTON', label: 'Start Forging', direction: 'right' },
    FINALIZE_FORGE_GUIDE: { targetId: 'FINALIZE_BUTTON', label: 'Complete Forge', direction: 'bottom' },
    OPEN_SHOP_TAB_GUIDE: { targetId: 'SHOP_TAB', label: 'Open Shop', direction: 'bottom' },
    OPEN_SHOP_SIGN_GUIDE: { targetId: 'SHOP_SIGN', label: 'Open the Shop', direction: 'bottom' },
};

const TUTORIAL_CONTEXT_SCRIPTS: Record<string, { speaker: string, text: string }> = {
    MARKET_GUIDE: { speaker: "Lockhart", text: "A forge without a roar is just a cold pile of stone. There should be a replacement furnace at the Market... let's head there." },
    FORGE_TAB_GUIDE: { speaker: "Lockhart", text: "The furnace is set. The air smells of potential again. I should prepare to craft my first blade." },
    SELECT_SWORD_GUIDE: { speaker: "Lockhart", text: "A Bronze Shortsword. A simple pattern, but a reliable test for this new unit." },
    OPEN_SHOP_TAB_GUIDE: { speaker: "Lockhart", text: "A blade without a wielder is just cold metal. Let's see if any travelers seek Lockhart steel." },
    OPEN_SHOP_SIGN_GUIDE: { speaker: "Lockhart", text: "The forge is alive. The shop must follow. Flip the sign and let them come." },
};

const TutorialOverlay = ({ step }: { step: string }) => {
    const { state, actions } = useGame();
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const animRef = useRef<number | null>(null);

    const config = TUTORIAL_STEPS_CONFIG[step];
    const script = TUTORIAL_CONTEXT_SCRIPTS[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.querySelector(`[data-tutorial-id="${config.targetId}"]`);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) setTargetRect(rect);
            else setTargetRect(null);
        } else {
            setTargetRect(null);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        if (!targetRect) return; 
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const duration = 1300;
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            const nextR = 2000 - (2000 - targetR) * easeOut;
            setAnimatedRadius(nextR);
            if (progress < 1) animRef.current = requestAnimationFrame(animate);
        };
        animRef.current = requestAnimationFrame(animate);
        return () => { if (animRef.current) cancelAnimationFrame(animRef.current); };
    }, [config?.targetId, !!targetRect]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    if (!config) return null;

    const { top = 0, left = 0, width = 0, height = 0 } = targetRect || {};
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles: React.CSSProperties = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';
    const cardinalBuffer = 12;

    switch (config.direction) {
        case 'top': pointerStyles = { left: centerX, top: top - cardinalBuffer, transform: 'translate(-50%, -100%)' }; iconRotation = 'rotate(180deg)'; animationClass = 'animate-bounce-reverse'; containerLayout = 'flex-col-reverse'; labelMargin = 'mb-3'; break;
        case 'bottom': pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' }; iconRotation = ''; animationClass = 'animate-bounce'; containerLayout = 'flex-col'; labelMargin = 'mt-3'; break;
        case 'left': pointerStyles = { left: left - cardinalBuffer, top: centerY, transform: 'translate(-100%, -50%)' }; iconRotation = 'rotate(90deg)'; animationClass = 'animate-bounce-x-reverse'; containerLayout = 'flex-row-reverse'; labelMargin = 'mr-3'; break;
        case 'right': pointerStyles = { left: left + width + cardinalBuffer, top: centerY, transform: 'translateY(-50%)' }; iconRotation = 'rotate(-90deg)'; animationClass = 'animate-bounce-x'; containerLayout = 'flex-row'; labelMargin = 'ml-3'; break;
        default: pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' }; iconRotation = ''; animationClass = 'animate-bounce'; containerLayout = 'flex-col'; labelMargin = 'mt-3'; break;
    }

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden">
            {/* Visual Darkening Mask */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs><mask id="tutorial-mask-layout"><rect width="100%" height="100%" fill="white" />{targetRect && <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />}</mask></defs>
                <rect width="100%" height="100%" fill={`rgba(0,0,0,0.75)`} mask="url(#tutorial-mask-layout)" />
            </svg>

            {/* Logical Interaction Walls (Blocking 4 sides around the target) */}
            {targetRect && (
                <div className="absolute inset-0 pointer-events-none">
                    {/* Top wall */}
                    <div className="absolute top-0 left-0 w-full pointer-events-auto bg-transparent" style={{ height: top }} />
                    {/* Bottom wall */}
                    <div className="absolute left-0 w-full pointer-events-auto bg-transparent" style={{ top: top + height, bottom: 0 }} />
                    {/* Left wall */}
                    <div className="absolute top-0 left-0 pointer-events-auto bg-transparent" style={{ top, height, width: left }} />
                    {/* Right wall */}
                    <div className="absolute top-0 pointer-events-auto bg-transparent" style={{ top, height, left: left + width, right: 0 }} />
                </div>
            )}

            {/* Pointer and Label */}
            {targetRect && (
                <div key={config.targetId} className="absolute animate-in fade-in zoom-in-95 duration-300" style={pointerStyles}>
                    <div className={`flex items-center ${containerLayout} ${animationClass}`}>
                        <Pointer className="w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20" style={{ transform: iconRotation }} />
                        <div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase rounded-full shadow-2xl border-2 border-amber-400`}>{config.label}</div>
                    </div>
                </div>
            )}

            {/* Dialogue Box Area */}
            {script && (
                <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl pointer-events-none z-[5000]">
                    <DialogueBox speaker={script.speaker} text={script.text} options={[]} className="w-full relative pointer-events-auto" />
                </div>
            )}
        </div>
    );
};

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const { state, actions } = useGame();
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showSkipConfirm, setShowSkipConfirm] = useState(false);
  const [isSleeping, setIsSleeping] = useState(false);
  const [isFadingOut, setIsFadingOut] = useState(false);
  const [zzzText, setZzzText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);
  const prevDayRef = useRef(state.stats.day);

  useEffect(() => {
    if (state.stats.day > prevDayRef.current) {
        setIsSleeping(true); setIsFadingOut(false); setActiveTab('FORGE');
        const sleepTimer = setTimeout(() => {
            setIsFadingOut(true);
            setTimeout(() => { setIsSleeping(false); setIsFadingOut(false); actions.closeRest(); }, 1000); 
        }, 1000); 
        prevDayRef.current = state.stats.day;
        return () => clearTimeout(sleepTimer);
    }
    prevDayRef.current = state.stats.day;
  }, [state.stats.day, actions]);

  useEffect(() => {
    if (isSleeping && !isFadingOut) {
        const frames = ['z', 'zz', 'zzz', 'zz']; let idx = 0;
        const timer = setInterval(() => { setZzzText(frames[idx % frames.length]); idx++; }, 250);
        return () => clearInterval(timer);
    } else { setZzzText(''); }
  }, [isSleeping, isFadingOut]);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      setShowRightArrow(canScroll && Math.ceil(scrollLeft) < (scrollWidth - clientWidth - 2));
    }
  }, []);

  useLayoutEffect(() => { setTimeout(updateArrows, 100); }, [updateArrows, activeTab]);
  useEffect(() => { window.addEventListener('resize', updateArrows); return () => window.removeEventListener('resize', updateArrows); }, [updateArrows]);

  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(exp => exp.status === 'COMPLETED').length;
  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;
  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);
  const unallocatedPointsCount = useMemo(() => state.knownMercenaries.filter(m => ['HIRED', 'ON_EXPEDITION', 'INJURED'].includes(m.status) && (m.bonusStatPoints || 0) > 0).length, [state.knownMercenaries]);

  const allTabs = [
    { id: 'FORGE' as const, icon: Anvil, label: 'Forge' },
    { id: 'INVENTORY' as const, icon: Package, label: 'Storage' },
    { id: 'MARKET' as const, icon: ShoppingBag, label: 'Market' },
    { id: 'SHOP' as const, icon: Coins, label: 'Shop', badge: activeTab !== 'SHOP' ? totalShopVisitors : 0 },
    { id: 'TAVERN' as const, icon: Beer, label: 'Tavern', badge: unallocatedPointsCount },
    { id: 'DUNGEON' as const, icon: MapIcon, label: 'Dungeon', badge: completedExpeditionsCount },
    { id: 'SIMULATION' as const, icon: Activity, label: 'Sim' },
  ];

  // Exclude scene modes that allow UI interaction
  const UI_PERMISSIVE_SCENES: TutorialSceneMode[] = ['MARKET', 'FORGE_TUTORIAL'];
  if (state.activeTutorialScene && !UI_PERMISSIVE_SCENES.includes(state.activeTutorialScene)) return <TutorialScene />;

  const isAnyTutorialActive = !!state.tutorialStep && state.hasCompletedPrologue && !state.isCrafting;

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden px-safe selection:bg-amber-500/30">
      {isSleeping && <div className={`fixed inset-0 z-[10000] bg-black transition-opacity ${isFadingOut ? 'opacity-0 duration-[1000ms]' : 'opacity-100'}`}>{!isFadingOut && <div className="absolute inset-0 flex flex-col items-center justify-center gap-4"><span className="text-amber-500 font-serif italic text-5xl md:text-7xl">{zzzText}</span><span className="text-stone-700 font-black uppercase text-[10px]">Resting...</span></div>}</div>}
      {isAnyTutorialActive && <div className="fixed top-4 right-4 z-[6000]"><button onClick={() => setShowSkipConfirm(true)} className="flex items-center gap-1.5 px-3 py-1.5 bg-stone-900 border border-stone-700 text-stone-300 rounded-full text-[10px] uppercase font-black shadow-2xl backdrop-blur-md active:scale-95"><FastForward className="w-3 h-3" /> Skip Tutorial</button></div>}
      {isAnyTutorialActive && state.tutorialStep && TUTORIAL_STEPS_CONFIG[state.tutorialStep] && <TutorialOverlay step={state.tutorialStep} />}

      {['CRAFT_RESULT_PROMPT', 'SHOP_INTRO_PROMPT'].includes(state.tutorialStep || '') && (
          <div className="fixed inset-0 z-[2500] flex flex-col justify-end items-center pb-6 md:pb-12 px-4 pointer-events-none">
              <div className="w-[92vw] md:w-[85vw] max-w-5xl pointer-events-auto">
                  <DialogueBox 
                    speaker="Lockhart" 
                    text={state.tutorialStep === 'CRAFT_RESULT_PROMPT' ? "Higher mastery grants permanent bonuses. Let's finish this piece." : "The forge is alive. The shop must follow. Let's head to the Shop tab."} 
                    options={[{ label: "Continue", action: () => actions.setTutorialStep(state.tutorialStep === 'CRAFT_RESULT_PROMPT' ? 'FINALIZE_FORGE_GUIDE' : 'OPEN_SHOP_TAB_GUIDE'), variant: 'primary' }]} 
                  />
              </div>
          </div>
      )}

      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'opacity-100'}`}><Header activeTab={activeTab} onTabChange={setActiveTab} onSettingsClick={() => setIsSettingsOpen(true)} /><div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden h-11 md:h-14"><div ref={scrollRef} onScroll={updateArrows} className="flex overflow-x-auto no-scrollbar flex-1 touch-pan-x snap-x scroll-smooth">{allTabs.map(tab => <button onClick={() => { if (!state.unlockedTabs.includes(tab.id) && !(tab.id === 'SHOP' && state.tutorialStep) && !(tab.id === 'FORGE' && state.tutorialStep === 'FORGE_TAB_GUIDE')) return actions.showToast("Facility locked."); if (state.tutorialStep === 'MARKET_GUIDE' && tab.id === 'MARKET') { actions.setTutorialStep('BROWSE_GOODS_GUIDE'); actions.setTutorialScene('MARKET'); } else if (state.tutorialStep === 'FORGE_TAB_GUIDE' && tab.id === 'FORGE') actions.setTutorialStep('SELECT_SWORD_GUIDE'); else if (state.tutorialStep === 'OPEN_SHOP_TAB_GUIDE' && tab.id === 'SHOP') actions.setTutorialStep('OPEN_SHOP_SIGN_GUIDE'); setActiveTab(tab.id); }} key={tab.id} data-tutorial-id={tab.id === 'MARKET' ? 'MARKET_TAB' : tab.id === 'FORGE' ? 'FORGE_TAB' : tab.id === 'SHOP' ? 'SHOP_TAB' : undefined} className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all shrink-0 ${activeTab === tab.id ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-[2100]' : 'border-transparent text-stone-500'} ${(!state.unlockedTabs.includes(tab.id) && !(tab.id === 'SHOP' && state.tutorialStep) && !(tab.id === 'FORGE' && state.tutorialStep === 'FORGE_TAB_GUIDE')) ? 'grayscale opacity-40' : ''}`}><tab.icon className="w-4 h-4 md:w-5 md:h-5" /><span className="font-bold text-[10px] md:text-sm uppercase">{tab.label}</span>{tab.badge ? <div className="absolute top-1 right-1 flex h-4 w-4 items-center justify-center rounded-full text-[8px] font-black text-white bg-red-600">{tab.badge}</div> : null}</button>)}</div></div></div>
      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0"><div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}><ForgeTab onNavigate={setActiveTab} /></div><div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}><ShopTab onNavigate={setActiveTab} /></div><div className={`h-full w-full ${activeTab === 'INVENTORY' ? 'block' : 'hidden'}`}><InventoryDisplay /></div><div className={`h-full w-full ${activeTab === 'MARKET' ? 'block' : 'hidden'}`}><MarketTab onNavigate={setActiveTab} /></div><div className={`h-full w-full ${activeTab === 'TAVERN' ? 'block' : 'hidden'}`}><TavernTab activeTab={activeTab} /></div><div className={`h-full w-full ${activeTab === 'DUNGEON' ? 'block' : 'hidden'}`}><DungeonTab /></div><div className={`h-full w-full ${activeTab === 'SIMULATION' ? 'block' : 'hidden'}`}><SimulationTab /></div></main>
      {state.toast?.visible && <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[10000] animate-in slide-in-from-bottom-4 pointer-events-none"><div onClick={actions.hideToast} className="bg-stone-900 border-2 border-amber-600/50 px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 pointer-events-auto cursor-pointer"><span className="text-stone-100 font-black text-xs md:text-sm uppercase tracking-widest">{state.toast.message}</span></div></div>}
      <EventModal /><SleepModal /><JournalModal /><DungeonResultModal /><CraftingResultModal /><SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onQuit={onQuit} onLoadRequest={onLoadFromSettings} /><TierUnlockModal /><TutorialCompleteModal /><ConfirmationModal isOpen={showSkipConfirm} title="Skip?" message="Unlock all systems immediately?" onConfirm={() => { actions.completeTutorial(); setShowSkipConfirm(false); }} onCancel={() => setShowSkipConfirm(false)} isDanger />
    </div>
  );
};

export default MainGameLayout;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number, enhancementCount: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  onTutorialTargetUpdate?: (rect: { x: number, y: number, w: number, h: number } | null) => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number | string;
  isTutorial?: boolean;
}

interface Point {
  x: number;
  y: number;
}

type SmithingTool = 'HAMMER' | 'TONGS';

export default class SmithingScene extends Phaser.Scene {
  declare public add: Phaser.GameObjects.GameObjectFactory;
  declare public tweens: Phaser.Tweens.TweenManager;
  declare public scale: Phaser.Scale.ScaleManager;
  declare public cameras: Phaser.Cameras.Scene2D.CameraManager;
  declare public input: Phaser.Input.InputPlugin;
  declare public time: Phaser.Time.Clock;
  declare public events: Phaser.Events.EventEmitter;
  declare public load: Phaser.Loader.LoaderPlugin;
  declare public textures: Phaser.Textures.TextureManager;
  declare public anims: Phaser.Animations.AnimationManager;
  declare public make: Phaser.GameObjects.GameObjectCreator;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;

  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private targetOutlineGraphics!: Phaser.GameObjects.Graphics;

  private progressBar!: Phaser.GameObjects.Graphics;
  private progBg!: Phaser.GameObjects.Graphics;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private qualityText!: Phaser.GameObjects.Text;

  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private billetContainer!: Phaser.GameObjects.Container;
  private billetImage?: Phaser.GameObjects.Image;
  private manualControlsContainer!: Phaser.GameObjects.Container;

  private toolSwitcherContainer!: Phaser.GameObjects.Container;
  private hammerBtn!: Phaser.GameObjects.Container;
  private tongsBtn!: Phaser.GameObjects.Container;
  private currentTool: SmithingTool = 'HAMMER';
  private hammerSprite!: Phaser.GameObjects.Image;

  private isRotatingManual = false;
  private isMovingManualX = false;
  private isMovingManualY = false;
  private startPointerPos = { x: 0, y: 0 };
  private startBilletPos = { x: 0, y: 0 };
  private startPointerAngle = 0;
  private startBilletRotation = 0;
  private isSnapped = false;
  private snapTween?: Phaser.Tweens.Tween;

  private hitPoly!: Phaser.Geom.Polygon;
  private spawnPoly!: Phaser.Geom.Polygon; 
  private outlineCache: Map<string, Point[]> = new Map();

  private centerX = 0;
  private centerY = 0;
  private hitX = 0;
  private hitY = 0;

  private viewW = 0;
  private viewH = 0;

  private score = 0;
  private targetScore = 100;
  private combo = 0;
  private lastHitTime = 0;
  private hitCooldown = 200;
  private isFinished = false;
  private isPlaying = false;
  private isReadyToStart = false;

  private currentQuality = 100;
  private perfectCount = 0;
  private enhancementCount = 0; 
  private pinnedTexts: Phaser.GameObjects.Text[] = [];

  private temperature = 0;
  private coolingRate = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number | string = 0;

  private startRadius = 180;
  private targetRadius = 45;
  private currentRadius = 180;
  private shrinkDuration = 2000;
  private ringTimer = 0;

  private currentTargetColor = 0xfabf24;
  private currentSpeedMult = 1.0;

  private readonly UI_PAD_TOP = 18;
  private readonly UI_PAD_SIDE = 16; 
  private readonly UI_PAD_BOTTOM = 28;
  private readonly UI_GAP = 18;

  private readonly TEMP_GAUGE_H_MIN = 80;

  private tempBarGraphics!: Phaser.GameObjects.Graphics;
  private tempBgGraphics!: Phaser.GameObjects.Graphics;
  private tempValueText!: Phaser.GameObjects.Text;

  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private bellowsBg!: Phaser.GameObjects.Arc;

  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping = false;

  private onComplete?: (score: number, enhancementCount: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;
  private onTutorialTargetUpdate?: (rect: { x: number, y: number, w: number, h: number } | null) => void;
  private isTutorial = false;

  private root!: Phaser.GameObjects.Container;

  private isPortrait = false;
  private lastPortrait?: boolean;
  private isRelayouting = false;

  private readonly BILLET_W_ON_ANVIL = 0.80; 
  private readonly BILLET_ANGLE_DEG = -12;

  private readonly SNAP_DIST_THRESHOLD = 25;
  private readonly SNAP_ANGLE_THRESHOLD = Phaser.Math.DegToRad(6);

  private readonly ANVIL_ORIGINAL_W = 1024;
  private readonly ANVIL_ORIGINAL_H = 559;
  private readonly ANVIL_HIT_X = 630;
  private readonly ANVIL_HIT_Y = 140;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.onTutorialTargetUpdate = data.onTutorialTargetUpdate;
    this.isTutorial = !!data.isTutorial;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.enhancementCount = 0;
    this.pinnedTexts = [];
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.outlineCache.clear();
    this.currentTool = 'HAMMER';
    this.isSnapped = true;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('billet_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
    this.load.image('icon_hammer', getAssetUrl('hammer.png'));
    this.load.image('icon_tongs', getAssetUrl('tongs.png'));
    this.load.image('hammer_strike', getAssetUrl('hammer.png'));
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map((i) => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }
    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);
    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.targetOutlineGraphics = this.add.graphics().setDepth(2).setAlpha(0.6);
    this.root.add(this.targetOutlineGraphics);

    this.billetContainer = this.add.container(0, 0).setDepth(3).setAngle(this.BILLET_ANGLE_DEG);

    if (this.textures.exists('billet_stage_0')) {
      this.billetImage = this.add.image(0, 0, 'billet_stage_0').setOrigin(0.5);
      this.billetContainer.add(this.billetImage);
    }
    this.root.add(this.billetContainer);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);
    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.hammerSprite = this.add.image(0, 0, 'hammer_strike').setOrigin(0.5, 0.9).setScale(0.5).setAlpha(0).setDepth(30);
    this.root.add(this.hammerSprite);

    this.setupUI();
    this.setupManualControls();
    this.setupToolSwitcher();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
      this.scale.off('resize', this.handleResize, this);
    });
    this.time.delayedCall(80, () => this.handleResize());

    this.setBilletStage(0);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const x = pointer.x; const y = pointer.y;
        const isBellowsClick = this.isBellowsClick(objs);
        const isHeatUpClick = this.isHeatUpClick(objs);
        const isSwitcherClick = objs.some(obj => obj.parentContainer === this.toolSwitcherContainer || obj === this.toolSwitcherContainer);

        if (isBellowsClick) { this.pumpBellows(); return; }
        if (isHeatUpClick) { this.requestHeatUp(); return; }
        if (isSwitcherClick) return;

        if (!this.isPlaying) { this.handleStartTap(x, y); return; }

        if (this.currentTool === 'HAMMER') {
          if (this.isPointerInHitArea(x, y)) {
            this.handleHammerSwing(x, y);
          } else { 
            const isOnAnvil = this.anvilImage.getBounds().contains(x, y);
            this.handleMiss(x, y, isOnAnvil ? 'STRUCK ANVIL' : 'MISS'); 
          }
        }
      }, this
    );

    this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
        if (this.isSnapped) return;
        if (this.isRotatingManual) {
            const currentAngle = Phaser.Math.Angle.Between(this.billetContainer.x, this.billetContainer.y, pointer.x, pointer.y);
            const delta = currentAngle - this.startPointerAngle;
            this.billetContainer.rotation = this.startBilletRotation + delta;
            this.checkMagnetSnap();
        } 
        else if (this.isMovingManualX) {
            const dx = pointer.x - this.startPointerPos.x;
            this.billetContainer.x = this.startBilletPos.x + dx;
            this.checkMagnetSnap();
        }
        else if (this.isMovingManualY) {
            const dy = pointer.y - this.startPointerPos.y;
            this.billetContainer.y = this.startBilletPos.y + dy;
            this.checkMagnetSnap();
        }
        if (this.isRotatingManual || this.isMovingManualX || this.isMovingManualY) {
            this.rebuildHitPoly();
            if (this.currentTool === 'TONGS') {
                this.drawTargetGuidelineFixed();
            }
        }
    });

    this.input.on('pointerup', () => {
        this.isRotatingManual = false;
        this.isMovingManualX = false;
        this.isMovingManualY = false;
    });

    this.switchTool('HAMMER');
  }

  private triggerHammerAnimation(x: number, y: number) {
    this.hammerSprite.setAlpha(1).setPosition(x + 50, y - 150).setAngle(15).setScale(0.5 * this.uiScale);
    this.tweens.add({
      targets: this.hammerSprite,
      x: x,
      y: y + 20,
      angle: -25,
      duration: 100,
      ease: 'Cubic.in',
      onComplete: () => {
        this.tweens.add({
          targets: this.hammerSprite,
          angle: -10,
          y: y + 10,
          alpha: 0,
          duration: 200,
          ease: 'Cubic.out'
        });
      }
    });
  }

  private setupToolSwitcher() {
    this.toolSwitcherContainer = this.add.container(0, 0).setDepth(30);
    this.root.add(this.toolSwitcherContainer);
    const createToolBtn = (x: number, y: number, key: string, tool: SmithingTool) => {
        const size = 110; 
        const bg = this.add.circle(0, 0, size/2, 0x1c1917, 0.9).setStrokeStyle(5, 0x57534e).setInteractive({ useHandCursor: true });
        const icon = this.add.image(0, 0, key).setDisplaySize(size * 0.65, size * 0.65);
        const container = this.add.container(x, y, [bg, icon]);
        bg.on('pointerdown', (p: any, lx: any, ly: any, event: any) => {
            event.stopPropagation();
            if (this.currentTool === tool && tool === 'HAMMER') {
                this.resetRing(); 
            } else {
                this.switchTool(tool);
            }
            this.tweens.add({ targets: container, scale: 0.85, duration: 80, yoyo: true });
        });
        return container;
    };
    this.hammerBtn = createToolBtn(0, 0, 'icon_hammer', 'HAMMER');
    this.tongsBtn = createToolBtn(125, 0, 'icon_tongs', 'TONGS'); 
    this.toolSwitcherContainer.add([this.hammerBtn, this.tongsBtn]);
  }

  private switchTool(tool: SmithingTool) {
    this.currentTool = tool;
    const hamBg = this.hammerBtn.list[0] as Phaser.GameObjects.Arc;
    const tonBg = this.tongsBtn.list[0] as Phaser.GameObjects.Arc;
    if (tool === 'HAMMER') {
        hamBg.setStrokeStyle(6, 0xfbbf24).setFillStyle(0x451a03, 1);
        tonBg.setStrokeStyle(4, 0x57534e).setFillStyle(0x1c1917, 0.9);
        if (this.manualControlsContainer) this.manualControlsContainer.setVisible(false);
        this.targetRing.setVisible(this.isPlaying);
        this.approachRing.setVisible(this.isPlaying);
        if (this.isPlaying) this.resetRing();
        this.targetOutlineGraphics.setVisible(false);
    } else {
        tonBg.setStrokeStyle(6, 0xfbbf24).setFillStyle(0x451a03, 1);
        hamBg.setStrokeStyle(4, 0x57534e).setFillStyle(0x1c1917, 0.9);
        if (this.manualControlsContainer) this.manualControlsContainer.setVisible(true);
        this.targetRing.setVisible(false);
        this.approachRing.setVisible(false);
        this.targetOutlineGraphics.setVisible(true);
        this.drawTargetGuidelineFixed();
    }
  }

  private setupManualControls() {
    this.manualControlsContainer = this.add.container(0, 0).setDepth(10);
    this.billetContainer.add(this.manualControlsContainer);
    const createBtn = (x: number, y: number, label: string, mode: 'X' | 'Y' | 'ROT') => {
        const size = 52;
        const isRot = mode === 'ROT';
        const bg = this.add.circle(0, 0, size/2, 0x1c1917, 0.8).setStrokeStyle(2, isRot ? 0x3b82f6 : 0xfbbf24, 0.8).setInteractive({ useHandCursor: true });
        const icon = this.add.text(0, 0, label, { fontSize: '24px', color: isRot ? '#60a5fa' : '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
        const btn = this.add.container(x, y, [bg, icon]);
        bg.on('pointerdown', (p: Phaser.Input.Pointer, lx: any, ly: any, event: any) => {
            event.stopPropagation();
            if (this.isSnapped) this.isSnapped = false;
            this.startPointerPos = { x: p.x, y: p.y };
            this.startBilletPos = { x: this.billetContainer.x, y: this.billetContainer.y };
            if (isRot) {
                this.isRotatingManual = true;
                this.startPointerAngle = Phaser.Math.Angle.Between(this.billetContainer.x, this.billetContainer.y, p.x, p.y);
                this.startBilletRotation = this.billetContainer.rotation;
            } else if (mode === 'X') {
                this.isMovingManualX = true;
            } else if (mode === 'Y') {
                this.isMovingManualY = true;
            }
            this.tweens.add({ targets: btn, scale: 0.8, duration: 100 });
        });
        bg.on('pointerup', () => { this.tweens.add({ targets: btn, scale: 1, duration: 100 }); });
        return btn;
    };
    const offsetX = 280; const offsetY = 120;
    const btnL = createBtn(-offsetX, 0, '←', 'X');
    const btnR = createBtn(offsetX, 0, '→', 'X');
    const btnU = createBtn(0, -offsetY, '↑', 'Y');
    const btnD = createBtn(0, offsetY, '↓', 'Y');
    const btnRotTL = createBtn(-offsetX, -offsetY, '🔄', 'ROT');
    const btnRotBR = createBtn(offsetX, offsetY, '🔄', 'ROT');
    this.manualControlsContainer.add([btnL, btnR, btnU, btnD, btnRotTL, btnRotBR]).setVisible(false);
  }

  private checkMagnetSnap() {
    if (this.currentTool !== 'TONGS') return;
    if (this.isSnapped || (this.snapTween && this.snapTween.isPlaying())) return;
    const anvilScale = this.anvilImage.scaleX;
    const offsetX = (this.ANVIL_HIT_X - this.ANVIL_ORIGINAL_W / 2) * anvilScale;
    const offsetY = (this.ANVIL_HIT_Y - this.ANVIL_ORIGINAL_H / 2) * anvilScale;
    const targetX = this.anvilImage.x + offsetX;
    const targetY = this.anvilImage.y + offsetY;
    const targetRot = Phaser.Math.DegToRad(this.BILLET_ANGLE_DEG);
    const dist = Phaser.Math.Distance.Between(this.billetContainer.x, this.billetContainer.y, targetX, targetY);
    const angleDiff = Math.abs(Phaser.Math.Angle.ShortestBetween(this.billetContainer.rotation, targetRot));
    if (dist < this.SNAP_DIST_THRESHOLD && angleDiff < this.SNAP_ANGLE_THRESHOLD) {
        this.isSnapped = true; this.isRotatingManual = false; this.isMovingManualX = false; this.isMovingManualY = false;
        this.snapTween = this.tweens.add({
            targets: this.billetContainer, x: targetX, y: targetY, rotation: targetRot, duration: 150, ease: 'Back.easeOut',
            onComplete: () => { this.rebuildHitPoly(); this.drawTargetGuidelineFixed(); this.createSparks(25, 0x10b981, 1.4, 'spark_perfect', targetX, targetY); }
        });
    }
  }

  private applyKickback(intensity: number) {
      if (!this.billetContainer) return;
      this.isSnapped = false;
      const posRange = intensity * 15; const angleRange = intensity * 8;
      const dx = Phaser.Math.FloatBetween(-posRange, posRange); const dy = Phaser.Math.FloatBetween(-posRange, posRange); const da = Phaser.Math.FloatBetween(-angleRange, angleRange);
      this.tweens.add({ targets: this.billetContainer, x: this.billetContainer.x + dx, y: this.billetContainer.y + dy, angle: this.billetContainer.angle + da, duration: 150, ease: 'Cubic.easeOut', onUpdate: () => this.rebuildHitPoly() });
  }

  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some((c) => objs.includes(c)); }

