const MAX_TEMP = 1500;
const IDLE_TEMP = 10;

type SequenceStep = 
    | 'IDLE' 
    | 'POST_REPLACE_TALK' 
    | 'WAIT_HEAT' 
    | 'HEAT_CONFIRM' 
    | 'WAIT_CONTINUE_BELLOWS' 
