import { GameState, InventoryItem } from '../../types/index';
import { materials } from '../../data/materials';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';

export const handleAcquireItem = (state: GameState, payload: { id: string; quantity: number }): GameState => {
    const { id, quantity } = payload;
    const itemDef = materials[id];
    if (!itemDef) return state;

    const existingItem = state.inventory.find(i => i.id === id);
    const newInventory = existingItem
    ? state.inventory.map(i => i.id === id ? { ...i, quantity: i.quantity + quantity } : i)
    : [...state.inventory, { ...itemDef, quantity } as InventoryItem];

    return {
    ...state,
    inventory: newInventory,
    logs: [`Acquired ${itemDef.name} x${quantity}.`, ...state.logs],
    };
};

export const handlePayCost = (state: GameState, payload: { gold?: number; items?: { id: string; count: number }[] }): GameState => {
    const { gold, items } = payload;
    let newGold = state.stats.gold;
    let newInventory = [...state.inventory];

    if (gold) newGold -= gold;
    if (items) {
        items.forEach(costItem => {
            newInventory = newInventory.map(invItem => {
                if (invItem.id === costItem.id) {
                    return { ...invItem, quantity: invItem.quantity - costItem.count };
                }
                return invItem;
            }).filter(i => i.quantity > 0);
        });
    }
    return {
        ...state,
        stats: { ...state.stats, gold: newGold },
        inventory: newInventory
    };
};

export const handleBuyMarketItems = (state: GameState, payload: { items: { id: string; count: number }[]; totalCost: number }): GameState => {
    const { items, totalCost } = payload;

    const newGold = state.stats.gold - totalCost;
    if (newGold < 0) return state; 

    let newInventory = [...state.inventory];
    let newTierLevel = state.stats.tierLevel;
    let newForgeState = { ...state.forge };
    let logUpdates: string[] = [`Bought supplies for ${totalCost} Gold.`];
    let newMarketStock = { ...state.marketStock };
    let newUnlockedTabs = [...state.unlockedTabs];

    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logUpdates.unshift("Access granted: Inventory facility is now operational.");
    }

    items.forEach(buyItem => {
            // Update stock
            newMarketStock[buyItem.id] = Math.max(0, (newMarketStock[buyItem.id] || 0) - buyItem.count);

            if (buyItem.id === 'scroll_t2') {
                newTierLevel = Math.max(newTierLevel, 2);
                logUpdates.unshift('Upgrade Complete: Market Tier 2 Unlocked!');
                return; 
            }
            if (buyItem.id === 'scroll_t3') {
                newTierLevel = Math.max(newTierLevel, 3);
                logUpdates.unshift('Upgrade Complete: Market Tier 3 Unlocked!');
                return; 
            }
            if (buyItem.id === 'furnace') {
                newForgeState.hasFurnace = true;
                if (newTierLevel === 0) newTierLevel = 1; 
                logUpdates.unshift('Furnace acquired! The restoration process has begun.');
                return; 
            }
            if (buyItem.id === 'workbench') {
                newForgeState.hasWorkbench = true;
                logUpdates.unshift('Workbench installed! You can now craft leather and wood equipment.');
                return;
            }
            const itemDef = materials[buyItem.id];
            if (itemDef) {
                const existingItem = newInventory.find(i => i.id === buyItem.id);
                if (existingItem) {
                    newInventory = newInventory.map(i => i.id === buyItem.id ? { ...i, quantity: i.quantity + buyItem.count } : i);
                } else {
                    newInventory.push({ ...itemDef, quantity: buyItem.count } as InventoryItem);
                }
            }
    });

    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: newGold, 
            tierLevel: newTierLevel,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseMarket: state.stats.dailyFinancials.expenseMarket + totalCost
            }
        },
        forge: newForgeState,
        inventory: newInventory,
        marketStock: newMarketStock,
        unlockedTabs: newUnlockedTabs,
        garrickAffinity: Math.min(100, state.garrickAffinity + 1), // 감사의 호감도 +1
        logs: [...logUpdates, ...state.logs]
    };
};

export const handleInstallFurnace = (state: GameState): GameState => {
    return {
        ...state,
        forge: { ...state.forge, hasFurnace: true },
        logs: ['The Furnace has been installed! The forge comes alive.', ...state.logs]
    };
};

export const handleSellItem = (state: GameState, payload: { itemId: string; count: number; price: number; equipmentInstanceId?: string; customer?: Mercenary }): GameState => {
    const { itemId, count, price, equipmentInstanceId, customer } = payload;

    let newInventory = [...state.inventory];
    let itemName = 'Item';
    let newKnownMercenaries = [...state.knownMercenaries];
    let logMessage = '';
    let newTutorialStep = state.tutorialStep;
    let newActiveCustomer = state.activeCustomer;
    let qualityBonus = 0;

    const isShopSale = !!customer;

    if (equipmentInstanceId) {
        const itemIndex = newInventory.findIndex(i => i.id === equipmentInstanceId);
        if (itemIndex > -1) {
            if (newInventory[itemIndex].isLocked) return state;

            const targetItem = newInventory[itemIndex];
            itemName = targetItem.name;

            // 품질 보너스 계산
            if (targetItem.equipmentData) {
                const q = targetItem.equipmentData.quality;
                if (q > 100) qualityBonus = 2; // 명품 보너스
                else if (q < 80) qualityBonus = -1; // 하급품 패널티
            }

            newInventory.splice(itemIndex, 1);
        }
    } else {
        const itemIndex = newInventory.findIndex(i => i.id === itemId);
        if (itemIndex > -1) {
            if (newInventory[itemIndex].isLocked) return state;
        }

        newInventory = newInventory.map(item => {
            if (item.id === itemId) {
                itemName = item.name;
                return { ...item, quantity: item.quantity - count };
            }
            return item;
        }).filter(i => i.quantity > 0);
    }

    if (customer) {
        const existingMercIdx = newKnownMercenaries.findIndex(m => m.id === customer.id);
        const isPipTutorial = newTutorialStep === 'SELL_ITEM_GUIDE' && customer.id === 'pip_green';

        // 최종 호감도 상승량 결정 (기본 2 + 품질 보너스)
        const baseAffinityGain = isPipTutorial ? 10 : 2;
        const finalAffinityGain = Math.max(1, baseAffinityGain + qualityBonus);

        if (existingMercIdx > -1) {
            const merc = { ...newKnownMercenaries[existingMercIdx] };
            merc.affinity = Math.min(100, (merc.affinity || 0) + finalAffinityGain); 
            merc.visitCount = (merc.visitCount || 0) + 1;
            merc.lastVisitDay = state.stats.day;
            newKnownMercenaries[existingMercIdx] = merc;

            const qualityNote = qualityBonus > 0 ? " (Masterwork Bonus!)" : qualityBonus < 0 ? " (Poor Quality Penalty)" : "";
            logMessage = `Sold ${itemName} to ${customer.name}. Affinity rose by ${finalAffinityGain}${qualityNote}.`;
        } else {
            const newMerc: Mercenary = {
                ...customer,
                affinity: finalAffinityGain,
                visitCount: 1,
                lastVisitDay: state.stats.day,
                expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
                currentXp: 0,
                xpToNextLevel: 100,
                status: 'VISITOR'
            };
            newKnownMercenaries.push(newMerc);
            logMessage = `Sold ${itemName} to ${customer.name}. (New Contact, Affinity +${finalAffinityGain})`;
        }

        if (newActiveCustomer && newActiveCustomer.mercenary.id === customer.id) {
            newActiveCustomer = {
                ...newActiveCustomer,
                mercenary: {
                    ...newActiveCustomer.mercenary,
                    affinity: Math.min(100, (newActiveCustomer.mercenary.affinity || 0) + finalAffinityGain)
                }
            };
        }

        // Fix: Updated tutorial step name from 'PIP_PRAISE' to 'PIP_PRAISE_DIALOG'
        if (isPipTutorial) {
            newTutorialStep = 'PIP_PRAISE_DIALOG';
        }
    } else {
        logMessage = `Sold ${itemName} for ${price} Gold.`;
    }

    return {
        ...state,
        inventory: newInventory,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold + price,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeShop: state.stats.dailyFinancials.incomeShop + (isShopSale ? price : 0),
                incomeInventory: state.stats.dailyFinancials.incomeInventory + (!isShopSale ? price : 0)
            }
        },
        knownMercenaries: newKnownMercenaries,
        activeCustomer: newActiveCustomer,
        tutorialStep: newTutorialStep,
        logs: [logMessage, ...state.logs]
    };
};

export const handleUseItem = (state: GameState, payload: { itemId: string; mercenaryId?: string }): GameState => {
    const { itemId, mercenaryId } = payload;
    const inventoryItem = state.inventory.find(i => i.id === itemId);

    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    let newStats = { ...state.stats };
    let newUnlockedRecipes = [...(state.unlockedRecipes || [])];
    let newKnownMercenaries = [...state.knownMercenaries];
    let logMsg = '';
    let itemUsed = false;

    if (itemId === 'energy_potion') {
        const recoverAmount = 25;
        if (newStats.energy >= newStats.maxEnergy) {
            return {
                ...state,
                toastQueue: [...state.toastQueue, `Blacksmith energy is already at maximum.`],
                logs: [`Energy is already full!`, ...state.logs]
            };
        }
        newStats.energy = Math.min(newStats.maxEnergy, newStats.energy + recoverAmount);
        logMsg = `Consumed Energy Potion. +${recoverAmount} Energy.`;
        itemUsed = true;
    } 
    else if (itemId === 'recipe_scroll_bronze_longsword') {
        const targetRecipeId = 'sword_bronze_long_t1';
        if (newUnlockedRecipes.includes(targetRecipeId)) {
            return {
                ...state,
                logs: [`You already know the techniques in this scroll.`, ...state.logs]
            };
        }
        newUnlockedRecipes.push(targetRecipeId);
        logMsg = `Studied the scroll. Bronze Longsword recipe unlocked!`;
        itemUsed = true;
    }
    else if (mercenaryId) {
        const mercIdx = newKnownMercenaries.findIndex(m => m.id === mercenaryId);
        if (mercIdx > -1) {
            const merc = { ...newKnownMercenaries[mercIdx] };
            if (itemId === 'hp_potion') {
                const heal = 50;
                if (merc.currentHp >= merc.maxHp) {
                    return { 
                        ...state, 
                        toastQueue: [...state.toastQueue, `${merc.name} is already at full health.`],
                        logs: [`${merc.name} is already at full health.`, ...state.logs] 
                    };
                }
                merc.currentHp = Math.min(merc.maxHp, merc.currentHp + heal);
                logMsg = `${merc.name} consumed HP Potion. Recovered ${heal} HP.`;
                itemUsed = true;
            } 
            else if (itemId === 'mp_potion') {
                const restore = 30;
                if (merc.currentMp >= merc.maxMp) {
                    return { 
                        ...state, 
                        toastQueue: [...state.toastQueue, `${merc.name} is already at full mana.`],
                        logs: [`${merc.name} is already at full MP.`, ...state.logs] 
                    };
                }
                merc.currentMp = Math.min(merc.maxMp, merc.currentMp + restore);
                logMsg = `${merc.name} consumed MP Potion. Recovered ${restore} MP.`;
                itemUsed = true;
            }
            else if (itemId === 'stamina_potion') {
                const stamina = 50;
                if ((merc.expeditionEnergy || 0) >= DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY) {
                    return { 
                        ...state, 
                        toastQueue: [...state.toastQueue, `${merc.name} is already at full stamina.`],
                        logs: [`${merc.name} is already at full stamina.`, ...state.logs] 
                    };
                }
                merc.expeditionEnergy = Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (merc.expeditionEnergy || 0) + stamina);
                logMsg = `${merc.name} consumed Stamina Potion. Recovered ${stamina} Stamina.`;
                itemUsed = true;
            }
            newKnownMercenaries[mercIdx] = merc;
        }
    }

    if (!itemUsed) return state;

    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    return {
        ...state,
        stats: newStats,
        inventory: newInventory,
        unlockedRecipes: newUnlockedRecipes,
        knownMercenaries: newKnownMercenaries,
        logs: [logMsg, ...state.logs]
    };
};

export const handleToggleLockItem = (state: GameState, payload: { itemId: string }): GameState => {
    const newInventory = state.inventory.map(item => {
        if (item.id === payload.itemId) {
            return { ...item, isLocked: !item.isLocked };
        }
        return item;
    });

    return {
        ...state,
        inventory: newInventory
    };
};

import { useState, useCallback, useMemo, useEffect } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EquipmentCategory, EquipmentItem } from '../../../../types';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { MASTERY_THRESHOLDS } from '../../../../config/mastery-config';
import { materials } from '../../../../data/materials';
import { getSmithingLevel, getUnlockedTier, getEnergyCost } from '../../../../utils/craftingLogic';

export const useForge = (onNavigate: (tab: any) => void) => {
  const { state, actions } = useGame();
  const { inventory, stats, isCrafting, craftingMastery, unlockedRecipes, tutorialStep, forgeTemperature, lastForgeTime } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [isSkillsExpanded, setIsSkillsExpanded] = useState(false);
  const [expandedSubCat, setExpandedSubCat] = useState<string | null>('SWORD');
  const [favorites, setFavorites] = useState<string[]>([]);
  const [isFavExpanded, setIsFavExpanded] = useState(true);
  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [quickCraftProgress, setQuickCraftProgress] = useState<number | null>(null);

  const smithingLevel = getSmithingLevel(stats.smithingExp);
  const workbenchLevel = getSmithingLevel(stats.workbenchExp);
  const unlockedSmithingTier = getUnlockedTier(smithingLevel);
  const unlockedWorkbenchTier = getUnlockedTier(workbenchLevel);

  const getInventoryCount = useCallback((id: string) => {
    return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const currentResidualTemp = useMemo(() => {
    const GLOBAL_COOLING_RATE_PER_SEC = 5;
    const timeDiffSec = (Date.now() - (lastForgeTime || 0)) / 1000;
    return Math.max(0, (forgeTemperature || 0) - (timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC));
  }, [forgeTemperature, lastForgeTime]);

  const canEnterForge = useMemo(() => {
    if (!selectedItem) return false;
    if (selectedItem.craftingType === 'FORGE') {
      const hasHeat = currentResidualTemp > 0;
      const hasFuel = getInventoryCount('charcoal') > 0;
      const isTutorialForging = tutorialStep === 'START_FORGING_GUIDE';
      return hasFurnace && (hasFuel || hasHeat || isTutorialForging);
    }
    return hasWorkbench;
  }, [selectedItem, hasFurnace, hasWorkbench, currentResidualTemp, getInventoryCount, tutorialStep]);

  const requiredEnergy = useMemo(() => {
    if (!selectedItem) return 20;
    const count = craftingMastery[selectedItem.id] || 0;
    return getEnergyCost(selectedItem, count);
  }, [selectedItem, craftingMastery]);

  const visibleItems = useMemo(() => {
    return EQUIPMENT_ITEMS.filter(item => {
      const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
      if (!isUnlocked) return false;
      const myTier = item.craftingType === 'FORGE' ? unlockedSmithingTier : unlockedWorkbenchTier;
      if (item.tier > myTier) return false;
      const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
      return subCatDef?.categoryId === activeCategory;
    });
  }, [activeCategory, unlockedSmithingTier, unlockedWorkbenchTier, unlockedRecipes]);

  const favoriteItems = useMemo(() => visibleItems.filter(item => favorites.includes(item.id)), [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
    const groups: Record<string, EquipmentItem[]> = {};
    visibleItems.forEach(item => {
      if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
      groups[item.subCategoryId].push(item);
    });
    return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
    return EQUIPMENT_SUBCATEGORIES.filter(sc => 
      sc.categoryId === activeCategory && (groupedItems[sc.id]?.length || 0) > 0
    );
  }, [activeCategory, groupedItems]);

  // Added masteryInfo calculation
  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count };
  }, [selectedItem, craftingMastery]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);
    setExpandedSubCat(cat === 'WEAPON' ? 'SWORD' : 'HELMET');
  }, []);

  const startCrafting = useCallback(() => {
    if (!selectedItem) return;
    const isRequirementMet = selectedItem.craftingType === 'FORGE' ? hasFurnace : hasWorkbench;

    if (!isRequirementMet) {
      actions.triggerEvent({
        id: 'NONE',
        title: 'Installation Required',
        description: `Requires ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'}.`,
        options: [{ label: 'Visit Market', action: () => onNavigate('MARKET') }, { label: 'Stay here', action: () => {} }]
      });
      return;
    }

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0) {
      actions.showToast("Insufficient materials.");
      return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
      actions.triggerEnergyHighlight();
      return;
    }

    actions.startCrafting(selectedItem);
    setIsPanelOpen(false);
  }, [selectedItem, hasFurnace, hasWorkbench, getInventoryCount, stats.energy, craftingMastery, actions, onNavigate]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
      actions.finishCrafting(selectedItem, score, bonus);
      // Fix: Updated 'CRAFT_RESULT_PROMPT' to 'CRAFT_RESULT_DIALOG' to match type definition
      if (tutorialStep === 'START_FORGING_GUIDE' && selectedItem.id === 'sword_bronze_t1') {
        actions.setTutorialStep('CRAFT_RESULT_DIALOG');
      }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions, tutorialStep]);

  const handleQuickCraft = useCallback(() => {
    if (!selectedItem) return;
    setQuickCraftProgress(0);
    const duration = 1500;
    const timer = setInterval(() => {
      setQuickCraftProgress(prev => {
        if (prev === null || prev >= 100) {
          clearInterval(timer);
          actions.startCrafting(selectedItem);
          actions.finishCrafting(selectedItem, 80, 0, 0.7);
          return null;
        }
        return prev + 2;
      });
    }, 30);
  }, [selectedItem, actions]);

  const updateTooltipPosition = (x: number, y: number) => {
    const viewportW = window.innerWidth;
    const viewportH = window.innerHeight;
    let finalX = x + 20;
    let finalY = y + 20;
    if (finalX + 240 > viewportW) finalX = x - 260;
    if (finalY + 160 > viewportH) finalY = y - 180;
    setTooltipPos({ x: finalX, y: finalY });
  };

  // Added missing handlers
  const handleSelectItem = useCallback((item: EquipmentItem) => {
      setSelectedItem(item);
      if (tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  }, [tutorialStep, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  return {
    state,
    actions,
    isCrafting,
    activeCategory,
    selectedItem,
    isPanelOpen,
    isSkillsExpanded,
    expandedSubCat,
    favorites,
    isFavExpanded,
    hoveredItem,
    tooltipPos,
    quickCraftProgress,
    smithingLevel,
    workbenchLevel,
    unlockedSmithingTier,
    unlockedWorkbenchTier,
    visibleSubCats,
    groupedItems,
    favoriteItems,
    canEnterForge,
    requiredEnergy: selectedItem ? getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0) : 20,
    getInventoryCount,
    masteryInfo,
    handlers: {
      setActiveCategory,
      setSelectedItem,
      setIsPanelOpen,
      setIsSkillsExpanded,
      setExpandedSubCat,
      setFavorites,
      setIsFavExpanded,
      setHoveredItem,
      setTooltipPos,
      handleCategoryChange,
      startCrafting,
      handleMinigameComplete,
      handleQuickCraft,
      updateTooltipPosition,
      handleSelectItem,
      handleMouseEnter,
      handleMouseMove,
      handleMouseLeave,
      toggleSubCategory: (id: string) => setExpandedSubCat(prev => prev === id ? null : id),
      toggleFavorite: (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
      }
    }
  };
};

