  private qualityText!: Phaser.GameObjects.Text;

  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private billetContainer!: Phaser.GameObjects.Container;
